<?php
declare(strict_types=1);require_once dirname(__DIR__).'/includes/cms.php';require_once dirname(__DIR__,3).'/includes/audit.php';exigirPermiso('academic.supervise');if(($_SERVER['REQUEST_METHOD']??'')!=='POST'||!validarTokenCsrf((string)($_POST['csrf_token']??''))){http_response_code(400);exit;}$pdo=obtenerConexion();$accion=(string)($_POST['accion']??'');try{$pdo->beginTransaction();if($accion==='curso'){$codigo=strtoupper(trim(strip_tags((string)($_POST['codigo']??''))));$nombre=trim(strip_tags((string)($_POST['nombre']??'')));$descripcion=trim(strip_tags((string)($_POST['descripcion']??'')));if($codigo===''||mb_strlen($codigo)>40||$nombre===''||mb_strlen($nombre)>180||mb_strlen($descripcion)>5000)throw new DomainException('Revisa los datos del curso.');$q=$pdo->prepare('INSERT INTO asignaturas(codigo,nombre,descripcion,creado_por) VALUES(:c,:n,:d,:u)');$q->execute(['c'=>$codigo,'n'=>$nombre,'d'=>$descripcion?:null,'u'=>$_SESSION['usuario_id']]);$entidad=(int)$pdo->lastInsertId();$evento='academic.course.created';}elseif($accion==='docente'){$a=cmsId($_POST['asignatura_id']??0);$d=cmsId($_POST['docente_id']??0);$q=$pdo->prepare("SELECT 1 FROM asignaturas a JOIN usuarios u ON u.id=:d AND u.rol='docente' AND u.estado='activo' WHERE a.id=:a");$q->execute(['d'=>$d,'a'=>$a]);if(!$q->fetchColumn())throw new DomainException('Curso o docente inválido.');$pdo->prepare("INSERT INTO docentes_asignaturas(docente_id,asignatura_id,asignado_por) VALUES(:d,:a,:u) ON DUPLICATE KEY UPDATE estado='activo',asignado_por=VALUES(asignado_por)")->execute(['d'=>$d,'a'=>$a,'u'=>$_SESSION['usuario_id']]);$entidad=$a;$evento='academic.teacher.assigned';}elseif($accion==='estudiante'){$a=cmsId($_POST['asignatura_id']??0);$d=cmsId($_POST['docente_id']??0);$e=cmsId($_POST['estudiante_id']??0);$q=$pdo->prepare("SELECT 1 FROM docentes_asignaturas da JOIN usuarios u ON u.id=:e AND u.rol='usuario' AND u.estado='activo' WHERE da.docente_id=:d AND da.asignatura_id=:a AND da.estado='activo'");$q->execute(['e'=>$e,'d'=>$d,'a'=>$a]);if(!$q->fetchColumn())throw new DomainException('La asignación docente o el estudiante no son válidos.');$pdo->prepare("INSERT INTO estudiantes_docentes(estudiante_id,docente_id,asignatura_id,matriculado_por) VALUES(:e,:d,:a,:u) ON DUPLICATE KEY UPDATE estado='activo',matriculado_por=VALUES(matriculado_por)")->execute(['e'=>$e,'d'=>$d,'a'=>$a,'u'=>$_SESSION['usuario_id']]);$entidad=$a;$evento='academic.student.enrolled';}else throw new DomainException('Acción académica inválida.');registrarAuditoria(['actor_user_id'=>$_SESSION['usuario_id'],'event_type'=>$evento,'module'=>'academic','entity_type'=>'course','entity_id'=>$entidad,'action'=>'create','result'=>'success','description'=>'Operación académica administrativa autorizada.'],$pdo);$pdo->commit();cmsFlash('exito','Operación académica completada.');}catch(Throwable $e){if($pdo->inTransaction())$pdo->rollBack();cmsFlash('error',$e instanceof DomainException?$e->getMessage():'No fue posible completar la operación.');}header('Location:index.php');
